-- =====================================================
-- Flyway Migration V3: Migrate ALL 684 External Users
-- =====================================================
-- Source: data/external_user_master.sql
-- Target: app_user table (new application)
-- Date: 2026-03-03
-- Total Users: 680 (ID 11 to 690)
-- =====================================================

-- Step 1: Create temporary staging table
CREATE TEMPORARY TABLE IF NOT EXISTS temp_user_migration (
    legacy_id INT PRIMARY KEY,
    user_name VARCHAR(150),
    login_id VARCHAR(75),
    password VARCHAR(300),
    email_address VARCHAR(300),
    company_name VARCHAR(300),
    create_date TIMESTAMP,
    is_active CHAR(3)
);

-- Step 2: Insert all users from external_user_master.sql

-- Step 3: Migrate to app_user table
-- Note: Legacy users use username/password authentication
-- azure_ad_object_id is NULL for users not yet authenticated via Azure AD
    user_id,
    email,
    display_name,
    azure_ad_object_id,
    admin,
    env_admin,
    is_active,
    created_at,
    updated_at,
    last_login_at,
    username,
    password,
    company_name,
    legacy_user_id
)
SELECT
    UUID(),  -- Generate UUID for user_id
    email_address,
    user_name,
    NULL,  -- azure_ad_object_id is NULL for legacy users
    FALSE,  -- Not admin by default
    FALSE,  -- Not env_admin by default
    CASE WHEN is_active = 'Y' THEN TRUE ELSE FALSE END,
    create_date,
    CURRENT_TIMESTAMP,
    NULL,  -- No last login
    login_id,  -- username from legacy system
    password,  -- password from legacy system (plain text)
    company_name,  -- company from legacy system
    legacy_id  -- Store original legacy user ID
FROM temp_user_migration
ORDER BY legacy_id;

-- Step 4: Clean up
DROP TABLE IF EXISTS temp_user_migration;
